29	export function claim(input: { policy: { items: { type: string; material?: string; enchantment?: number }[] }; incident: { cause?: string; damages: { itemType: string; amount: number }[] } }): number {
30	  const damages = input.incident.damages;
31	  const policyItems = input.policy.items;
32	  const totalPayout = damages.reduce((payoutSoFar, damage) => {
33	    if (damage.amount < 0) {
34	      throw new Error(`Damage amount must be non-negative: ${damage.amount}`);
35	    }
36	    const policyItem = policyItems.find((item) => item.type === damage.itemType);
37	    if (policyItem === undefined) {
38	      throw new Error(`Claim references item type not in policy: ${damage.itemType}`);
39	    }
40	    const hasHighEnchantment = (policyItem.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
41	    const reimbursable = hasHighEnchantment ? damage.amount * HIGH_ENCHANTMENT_PAYOUT_RATE : damage.amount;
42	    return payoutSoFar + (reimbursable - DEDUCTIBLE_PER_ITEM);
43	  }, 0);
44	  return Math.floor(totalPayout);
45	}
